// Utility to extract and send game data to Captivate from ProducerDashboard
import { sendVariablesToCaptivate, sendRenderCommand } from './useCaptivate';

// Helper to format character names for filenames
function toSlug(str) {
  return (str || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');
}

function getCardImageUrls(card) {
  const characterSlug = toSlug(card.character);
  const raritySlug = (card.rarity || '').toLowerCase();
  return {
    card_imageUrl: characterSlug && raritySlug ? `${characterSlug}-${raritySlug}.png` : '',
    card_socialImageUrl: characterSlug ? `${characterSlug}.png` : '',
    card_characterUrl: characterSlug ? `${characterSlug}-classic-shrinkwrapped.png` : '',
  };
}

const RARITY_COLORS = {
  'core': '#E4CE13',
  'rare': '#783F22',
  'very rare': '#C05316',
  'epic': '#2DAD7C',
  'spectacular': '#B1A5D0',
};

export function getColorForRarity(rarity) {
  if (!rarity) return '';
  return RARITY_COLORS[rarity.toLowerCase()] || '';
}

// Helper function to prepare card variables
function prepareCardVariables(roundData, prefix = '') {
  const card1 = roundData.C1 || {};
  const card2 = roundData.C2 || {};

  const card1Urls = getCardImageUrls(card1);
  const card2Urls = getCardImageUrls(card2);

  return {
    // Card 1
    [`${prefix}card1_aura`]: card1.Aura ?? 0,
    [`${prefix}card1_skill`]: card1.Skill ?? 0,
    [`${prefix}card1_stamina`]: card1.Stamina ?? 0,
    [`${prefix}card1_character`]: card1.character ?? '',
    [`${prefix}card1_rarity`]: card1.rarity ?? '',
    [`${prefix}card1_score`]: card1.Score !== undefined ? Math.round(card1.Score) : 0,
    [`${prefix}card1_color`]: getColorForRarity(card1.rarity),
    [`${prefix}card1_imageUrl`]: card1Urls.card_imageUrl,
    [`${prefix}card1_socialImageUrl`]: card1Urls.card_socialImageUrl,
    [`${prefix}card1_characterUrl`]: card1Urls.card_characterUrl,
    [`${prefix}card1_rarityImageUrl`]: card1.rarityImage ?? '',
    [`${prefix}card1_tier`]: card1.tier ?? '',
    [`${prefix}card1_quote`]: card1.quote ?? '',
    [`${prefix}card1_vfc`]: card1.vfc ?? '',
    // Card 2
    [`${prefix}card2_aura`]: card2.Aura ?? 0,
    [`${prefix}card2_skill`]: card2.Skill ?? 0,
    [`${prefix}card2_stamina`]: card2.Stamina ?? 0,
    [`${prefix}card2_character`]: card2.character ?? '',
    [`${prefix}card2_rarity`]: card2.rarity ?? '',
    [`${prefix}card2_score`]: card2.Score !== undefined ? Math.round(card2.Score) : 0,
    [`${prefix}card2_color`]: getColorForRarity(card2.rarity),
    [`${prefix}card2_imageUrl`]: card2Urls.card_imageUrl,
    [`${prefix}card2_socialImageUrl`]: card2Urls.card_socialImageUrl,
    [`${prefix}card2_characterUrl`]: card2Urls.card_characterUrl,
    [`${prefix}card2_rarityImageUrl`]: card2.rarityImage ?? '',
    [`${prefix}card2_tier`]: card2.tier ?? '',
    [`${prefix}card2_quote`]: card2.quote ?? '',
    [`${prefix}card2_vfc`]: card2.vfc ?? '',
  };
}

// Send current round data (for immediate display)
export async function sendCurrentRoundDataToCaptivate(roundData) {
  console.log('đźźˇ sendCurrentRoundDataToCaptivate called with:', roundData);

  const variables = prepareCardVariables(roundData);

  console.log('đźźˇ About to send current round variables to Captivate:', variables);
  const result = await sendVariablesToCaptivate(variables);
  console.log('đźźˇ sendVariablesToCaptivate result:', result);
  return result;
}

// Send next round data (for pre-rendering)
export async function sendNextRoundDataToCaptivate(roundData) {
  console.log('đź”® sendNextRoundDataToCaptivate called with:', roundData);

  const variables = prepareCardVariables(roundData, 'next_');

  console.log('đź”® About to send next round variables to Captivate for rendering:', variables);
  const result = await sendRenderCommand(variables);
  console.log('đź”® sendRenderCommand result:', result);
  return result;
}

// Send both current and next round data
export async function sendBothRoundsDataToCaptivate(currentRoundData, nextRoundData = null) {
  console.log('đźŽŻ sendBothRoundsDataToCaptivate called');

  const results = {};

  // Send current round data
  if (currentRoundData) {
    results.current = await sendCurrentRoundDataToCaptivate(currentRoundData);
  }

  // Send next round data for pre-rendering
  if (nextRoundData) {
    results.next = await sendNextRoundDataToCaptivate(nextRoundData);
  }

  return results;
}

// Send player and winner data (after round winner is decided)
export async function sendPlayerAndWinnerDataToCaptivate(gameState, roundObj) {
  console.log('đź”µ sendPlayerAndWinnerDataToCaptivate called with:', { gameState, roundObj });

  // Player 1 and 2
  const player1 = gameState.player1 || {};
  const player2 = gameState.player2 || {};

  console.log('đź”µ Player data extracted:', { player1, player2 });

  // Winner card - only if there's a round with a winner
  let winnerCard = null;
  if (roundObj?.winner === 'P1') winnerCard = roundObj.C1;
  if (roundObj?.winner === 'P2') winnerCard = roundObj.C2;

  const winnerUrls = getCardImageUrls(winnerCard || {});

  const variables = {
    // Player 1
    player1_name: player1.name ?? '',
    player1_handle: player1.handle ?? '',
    player1_avatarUrl: player1.avatarUrl ?? '',
    player1_aura: player1.score?.aura ?? 0,
    player1_skill: player1.score?.skill ?? 0,
    player1_stamina: player1.score?.stamina ?? 0,
    // Player 2
    player2_name: player2.name ?? '',
    player2_handle: player2.handle ?? '',
    player2_avatarUrl: player2.avatarUrl ?? '',
    player2_aura: player2.score?.aura ?? 0,
    player2_skill: player2.score?.skill ?? 0,
    player2_stamina: player2.score?.stamina ?? 0,
    // Winner card (empty if no winner yet)
    winner_character: winnerCard?.character ?? '',
    winner_imageUrl: winnerUrls.card_imageUrl,
    winner_socialImageUrl: winnerUrls.card_socialImageUrl,
    winner_characterUrl: winnerUrls.card_characterUrl,
    winner_rarity: winnerCard?.rarity ?? '',
    winner_rarityImageUrl: winnerCard?.rarityImage ?? '',
    winner_color: getColorForRarity(winnerCard?.rarity),
    winner_score: winnerCard?.Score !== undefined ? Math.round(winnerCard.Score) : 0,
    winner_aura: winnerCard?.Aura ?? 0,
    winner_skill: winnerCard?.Skill ?? 0,
    winner_stamina: winnerCard?.Stamina ?? 0,
    winner_tier: winnerCard?.tier ?? '',
    winner_quote: winnerCard?.quote ?? '',
    winner_vfc: winnerCard?.vfc ?? '',
  };

  console.log('đź”µ About to send player variables to Captivate:', variables);
  const result = await sendVariablesToCaptivate(variables);
  console.log('đź”µ sendVariablesToCaptivate result:', result);
  return result;
}

// Legacy function for backward compatibility
export async function sendRoundDataToCaptivate(roundData) {
  console.log('âš ď¸Ź Legacy sendRoundDataToCaptivate called - use sendCurrentRoundDataToCaptivate instead');
  return sendCurrentRoundDataToCaptivate(roundData);
}
